mapper.select:
SELECT a.id, a.project_id AS "projectId", a.title, a.description, a.issue_attachments AS "issueAttachments", a.assignee, a.due_date AS "dueDate", a.confirmed, a.resolution, a.status, a.created_by AS "createdBy", a.created_at AS "createdAt", a.updated_by AS "updatedBy", a.updated_at AS "updatedAt", p.code AS "projectCode", p.name AS "projectName", creator.name AS "createdByName", assignee.name AS "assigneeName" FROM issue_ticket a LEFT JOIN project p ON p.id = a.project_id LEFT JOIN sys_account creator ON creator.id = a.created_by LEFT JOIN sys_account assignee ON assignee.id = a.assignee
AND a.project_id = #{params.projectId}
AND p.name LIKE CONCAT('%', #{params.projectName}, '%') AND p.name LIKE '%' || #{params.projectName} || '%'
AND a.title LIKE CONCAT('%', #{params.keyword}, '%') AND a.title LIKE '%' || #{params.keyword} || '%'
AND a.status = #{params.status}
ORDER BY a.created_at DESC, a.id DESC
